import json
from typing import Dict, Optional
import time

class JokeGenerator:
    """Random Joke Generator using multiple APIs"""

    def __init__(self):
        self.joke_apis = {
            'official_jokes': 'https://official-joke-api.appspot.com/random_joke',
            'jokesapi': 'https://v2.jokeapi.dev/joke/Any',
            'dad_jokes': 'https://icanhazdadjoke.com/',
            'jokes_ninja': 'https://api.api-ninjas.com/v1/jokes',
        }
        self.timeout = 5
        self.headers = {'User-Agent': 'JokeGenerator/1.0'}

    def get_joke_from_official_api(self) -> Optional[Dict]:
        """Dapatkan joke dari Official Joke API"""
        try:
            response = requests.get(
                self.joke_apis['official_jokes'],
                timeout=self.timeout,
                headers=self.headers
            )
            response.raise_for_status()
            data = response.json()

            return {
                'source': 'Official Joke API',
                'setup': data.get('setup', ''),
                'punchline': data.get('punchline', ''),
                'type': data.get('type', 'general'),
                'full_joke': f"{data.get('setup', '')} {data.get('punchline', '')}"
            }
        except Exception as e:
            print(f"Error from Official Joke API: {e}")
            return None

    def get_joke_from_jokesapi(self) -> Optional[Dict]:
        """Dapatkan joke dari Jokes API"""
        try:
            response = requests.get(
                self.joke_apis['jokesapi'],
                timeout=self.timeout,
                headers=self.headers
            )
            response.raise_for_status()
            data = response.json()

            if data.get('error'):
                return None

            if data.get('type') == 'twopart':
                joke_text = f"{data.get('setup', '')} {data.get('delivery', '')}"
            else:
                joke_text = data.get('joke', '')

            return {
                'source': 'Jokes API',
                'setup': data.get('setup', ''),
                'punchline': data.get('delivery', ''),
                'type': data.get('category', 'general'),
                'full_joke': joke_text
            }
        except Exception as e:
            print(f"Error from Jokes API: {e}")
            return None

    def get_joke_from_dad_jokes(self) -> Optional[Dict]:
        """Dapatkan joke dari Dad Jokes API"""
        try:
            response = requests.get(
                self.joke_apis['dad_jokes'],
                timeout=self.timeout,
                headers={'Accept': 'application/json', **self.headers}
            )
            response.raise_for_status()
            data = response.json()

            return {
                'source': 'Dad Jokes API',
                'setup': '',
                'punchline': '',
                'type': 'dad_joke',
                'full_joke': data.get('joke', '')
            }
        except Exception as e:
            print(f"Error from Dad Jokes API: {e}")
            return None

    def get_random_joke(self, attempt: int = 0, max_attempts: int = 3) -> Optional[Dict]:
        """
        Dapatkan joke random dari salah satu API
        Coba multiple APIs jika satu gagal
        """
        apis = list(self.joke_apis.keys())

        if attempt >= max_attempts:
            return self._get_fallback_joke()

        # Coba setiap API secara bergantian
        for api_name in apis:
            try:
                if api_name == 'official_jokes':
                    joke = self.get_joke_from_official_api()
                elif api_name == 'jokesapi':
                    joke = self.get_joke_from_jokesapi()
                elif api_name == 'dad_jokes':
                    joke = self.get_joke_from_dad_jokes()
                elif api_name == 'jokes_ninja':
                    joke = self.get_joke_from_jokes_ninja()

                if joke:
                    return joke
            except Exception as e:
                print(f"Error with {api_name}: {e}")
                continue

        # Jika semua gagal, coba lagi atau return fallback
        if attempt < max_attempts:
            time.sleep(1)
            return self.get_random_joke(attempt + 1, max_attempts)

        return self._get_fallback_joke()

    def get_joke_from_jokes_ninja(self) -> Optional[Dict]:
        """Dapatkan joke dari Jokes Ninja API (tidak memerlukan API key untuk basic)"""
        try:
            response = requests.get(
                self.joke_apis['jokes_ninja'],
                timeout=self.timeout,
                headers=self.headers
            )
            response.raise_for_status()
            data = response.json()

            if isinstance(data, list) and len(data) > 0:
                joke_data = data[0]
                return {
                    'source': 'Jokes Ninja API',
                    'setup': '',
                    'punchline': '',
                    'type': 'general',
                    'full_joke': joke_data.get('joke', '')
                }
            return None
        except Exception as e:
            print(f"Error from Jokes Ninja API: {e}")
            return None

    def _get_fallback_joke(self) -> Dict:
        """Fallback joke jika semua API gagal"""
        fallback_jokes = [
            {
                'setup': 'Why did the scarecrow win an award?',
                'punchline': 'Because he was outstanding in his field!',
                'full_joke': 'Why did the scarecrow win an award? Because he was outstanding in his field!',
                'type': 'general',
                'source': 'Fallback Joke'
            },
            {
                'setup': 'What do you call a fake noodle?',
                'punchline': 'An impasta!',
                'full_joke': 'What do you call a fake noodle? An impasta!',
                'type': 'general',
                'source': 'Fallback Joke'
            },
            {
                'setup': 'Why don\'t scientists trust atoms?',
                'punchline': 'Because they make up everything!',
                'full_joke': 'Why don\'t scientists trust atoms? Because they make up everything!',
                'type': 'general',
                'source': 'Fallback Joke'
            },
        ]
        import random
        return random.choice(fallback_jokes)

    def get_formatted_joke(self) -> str:
        """Dapatkan joke yang sudah di-format"""
        joke = self.get_random_joke()

        if not joke:
            return "Sorry, couldn't fetch a joke at the moment!"

        formatted = f"""
╔════════════════════════════════════════╗
║           😂 RANDOM JOKE 😂             ║
╚════════════════════════════════════════╝

{joke['full_joke']}

📌 Source: {joke['source']}
📂 Category: {joke['type']}
"""
        return formatted

    def save_joke_to_file(self, filename: str = 'jokes.json') -> bool:
        """Simpan joke ke file JSON"""
        try:
            joke = self.get_random_joke()

            # Load existing jokes
            try:
                with open(filename, 'r') as f:
                    jokes = json.load(f)
            except FileNotFoundError:
                jokes = []

            # Add timestamp
            joke['timestamp'] = time.strftime('%Y-%m-%d %H:%M:%S')
            jokes.append(joke)

            # Save to file
            with open(filename, 'w') as f:
                json.dump(jokes, f, indent=2)

            print(f"✅ Joke saved to {filename}")
            return True
        except Exception as e:
            print(f"❌ Error saving joke: {e}")
            return False

    def get_multiple_jokes(self, count: int = 5) -> list:
        """Dapatkan multiple jokes"""
        jokes = []
        for i in range(count):
            joke = self.get_random_joke()
            if joke:
                jokes.append(joke)
            time.sleep(0.5)  # Delay between requests

        return jokes

    def print_joke_statistics(self, filename: str = 'jokes.json'):
        """Tampilkan statistik jokes yang sudah disimpan"""
        try:
            with open(filename, 'r') as f:
                jokes = json.load(f)

            print("\n" + "="*50)
            print("📊 JOKE STATISTICS")
            print("="*50)
            print(f"Total Jokes: {len(jokes)}")

            # Count by source
            sources = {}
            categories = {}

            for joke in jokes:
                source = joke.get('source', 'Unknown')
                category = joke.get('type', 'Unknown')

                sources[source] = sources.get(source, 0) + 1
                categories[category] = categories.get(category, 0) + 1

            print("\n📌 By Source:")
            for source, count in sources.items():
                print(f"   • {source}: {count}")

            print("\n📂 By Category:")
            for category, count in categories.items():
                print(f"   • {category}: {count}")

            print("="*50 + "\n")
        except FileNotFoundError:
            print("❌ No jokes file found. Save some jokes first!")


def main():
    """Main function untuk test Joke Generator"""
    print("🤖 Welcome to Random Joke Generator!")
    print("="*50)

    generator = JokeGenerator()

    while True:
        print("\n📋 Menu Options:")
        print("1. 😂 Get a Random Joke")
        print("2. 🔢 Get Multiple Jokes (5)")
        print("3. 💾 Save Current Joke")
        print("4. 📊 View Statistics")
        print("5. 📚 View Saved Jokes")
        print("6. ❌ Exit")

        choice = input("\nChoose an option (1-6): ").strip()

        if choice == '1':
            print(generator.get_formatted_joke())

        elif choice == '2':
            print("\n⏳ Fetching 5 jokes...")
            jokes = generator.get_multiple_jokes(5)

            for i, joke in enumerate(jokes, 1):
                print(f"\n{'='*50}")
                print(f"Joke {i}:")
                print(f"{'='*50}")
                print(joke['full_joke'])
                print(f"📌 Source: {joke['source']}")
                print(f"📂 Category: {joke['type']}")

        elif choice == '3':
            generator.save_joke_to_file()
            print("\n✅ Joke saved successfully!")

        elif choice == '4':
            generator.print_joke_statistics()

        elif choice == '5':
            try:
                with open('jokes.json', 'r') as f:
                    jokes = json.load(f)

                print(f"\n📚 Total Saved Jokes: {len(jokes)}\n")
                for i, joke in enumerate(jokes[-5:], 1):  # Show last 5
                    print(f"{i}. {joke['full_joke']}")
                    print(f"   📌 {joke['source']} | 📂 {joke['type']}")
                    print(f"   ⏰ {joke.get('timestamp', 'N/A')}\n")
            except FileNotFoundError:
                print("❌ No saved jokes found!")

        elif choice == '6':
            print("\n👋 Thanks for using Joke Generator! Goodbye!")
            break

        else:
            print("❌ Invalid choice! Please try again.")


if __name__ == '__main__':
    main()
