import json
from flask import Flask, jsonify, render_template_string
from joke_generator import JokeGenerator
import os

app = Flask(__name__)
generator = JokeGenerator()

# HTML Template untuk web interface
HTML_TEMPLATE = """
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Random Joke Generator 😂</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
            min-height: 100vh;
            display: flex;
            justify-content: center;
            align-items: center;
            padding: 20px;
        }

        .container {
            background: white;
            border-radius: 20px;
            box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);
            padding: 40px;
            max-width: 600px;
            width: 100%;
        }

        .header {
            text-align: center;
            margin-bottom: 40px;
        }

        .header h1 {
            font-size: 2.5em;
            color: #333;
            margin-bottom: 10px;
        }

        .header p {
            color: #666;
            font-size: 1.1em;
        }

        .joke-box {
            background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
            color: white;
            padding: 30px;
            border-radius: 15px;
            margin-bottom: 30px;
            min-height: 150px;
            display: flex;
            flex-direction: column;
            justify-content: center;
            text-align: center;
            font-size: 1.2em;
            line-height: 1.6;
        }

        .joke-text {
            margin-bottom: 20px;
            min-height: 80px;
            display: flex;
            align-items: center;
            justify-content: center;
        }

        .joke-info {
            font-size: 0.9em;
            opacity: 0.9;
            border-top: 1px solid rgba(255, 255, 255, 0.3);
            padding-top: 15px;
        }

        .buttons {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 15px;
            margin-bottom: 20px;
        }

        button {
            padding: 12px 24px;
            border: none;
            border-radius: 10px;
            font-size: 1em;
            cursor: pointer;
            transition: all 0.3s ease;
            font-weight: 600;
        }

        .btn-primary {
            background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
            color: white;
            grid-column: 1 / -1;
        }

        .btn-primary:hover {
            transform: translateY(-2px);
            box-shadow: 0 10px 20px rgba(102, 126, 234, 0.4);
        }

        .btn-secondary {
            background: #f0f0f0;
            color: #333;
        }

        .btn-secondary:hover {
            background: #e0e0e0;
        }

        .loading {
            display: none;
            text-align: center;
            color: #667eea;
            font-weight: 600;
        }

        .error {
            background: #fee;
            color: #c33;
            padding: 15px;
            border-radius: 10px;
            margin-bottom: 20px;
            display: none;
        }

        .stats {
            background: #f9f9f9;
            padding: 20px;
            border-radius: 10px;
            margin-top: 20px;
            border-left: 4px solid #667eea;
        }

        .stats h3 {
            margin-bottom: 10px;
            color: #333;
        }

        .stats-item {
            display: flex;
            justify-content: space-between;
            padding: 8px 0;
            border-bottom: 1px solid #eee;
        }

        .stats-item:last-child {
            border-bottom: none;
        }

        .spinner {
            border: 4px solid #f3f3f3;
            border-top: 4px solid #667eea;
            border-radius: 50%;
            width: 30px;
            height: 30px;
            animation: spin 1s linear infinite;
            margin: 0 auto;
        }

        @keyframes spin {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
        }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h1>😂 Joke Generator</h1>
            <p>Get a random laugh every time!</p>
        </div>

        <div class="error" id="error"></div>

        <div class="joke-box">
            <div class="joke-text" id="jokeText">
                Click "Get Joke" to start! 🎉
            </div>
            <div class="joke-info" id="jokeInfo"></div>
        </div>

        <div class="loading" id="loading">
            <div class="spinner"></div>
            <p>Loading joke...</p>
        </div>

        <div class="buttons">
            <button class="btn-primary" onclick="getJoke()">😂 Get a Joke</button>
            <button class="btn-secondary" onclick="saveJoke()">💾 Save</button>
            <button class="btn-secondary" onclick="toggleStats()">📊 Stats</button>
        </div>

        <div class="stats" id="stats" style="display: none;">
            <h3>📈 Statistics</h3>
            <div id="statsContent">Loading...</div>
        </div>
    </div>

    <script>
        let currentJoke = null;

        function showLoading(show = true) {
            document.getElementById('loading').style.display = show ? 'block' : 'none';
        }

        function showError(message) {
            const errorDiv = document.getElementById('error');
            errorDiv.textContent = message;
            errorDiv.style.display = 'block';
            setTimeout(() => {
                errorDiv.style.display = 'none';
            }, 5000);
        }

        function getJoke() {
            showLoading(true);

            fetch('/api/joke')
                .then(response => {
                    if (!response.ok) throw new Error('Failed to fetch joke');
                    return response.json();
                })
                .then(data => {
                    currentJoke = data;
                    document.getElementById('jokeText').textContent = data.full_joke;
                    document.getElementById('jokeInfo').innerHTML = 
                        `📌 Source: ${data.source}<br>📂 Category: ${data.type}`;
                    showLoading(false);
                })
                .catch(error => {
                    showError('Error: ' + error.message);
                    showLoading(false);
                });
        }

        function saveJoke() {
            if (!currentJoke) {
                showError('Please get a joke first!');
                return;
            }

            fetch('/api/save', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify(currentJoke)
            })
            .then(response => response.json())
            .then(data => {
                if (data.success) {
                    alert('✅ Joke saved successfully!');
                } else {
                    showError('Failed to save joke');
                }
            })
            .catch(error => showError('Error: ' + error.message));
        }

        function toggleStats() {
            const statsDiv = document.getElementById('stats');
            if (statsDiv.style.display === 'none') {
                loadStats();
                statsDiv.style.display = 'block';
            } else {
                statsDiv.style.display = 'none';
            }
        }

        function loadStats() {
            fetch('/api/stats')
                .then(response => response.json())
                .then(data => {
                    let html = `<div class="stats-item">
                        <span>Total Jokes:</span>
                        <strong>${data.total}</strong>
                    </div>`;

                    if (data.sources) {
                        html += '<h4 style="margin-top: 10px; margin-bottom: 8px;">By Source:</h4>';
                        for (const [source, count] of Object.entries(data.sources)) {
                            html += `<div class="stats-item">
                                <span>${source}</span>
                                <strong>${count}</strong>
                            </div>`;
                        }
                    }

                    document.getElementById('statsContent').innerHTML = html;
                })
                .catch(error => showError('Error loading stats: ' + error.message));
        }

        // Load initial joke
        window.onload = getJoke;
    </script>
</body>
</html>
"""

@app.route('/')
def index():
    """Render web interface"""
    return render_template_string(HTML_TEMPLATE)

@app.route('/api/joke', methods=['GET'])
def api_get_joke():
    """API endpoint untuk get random joke"""
    joke = generator.get_random_joke()

    if not joke:
        return jsonify({'error': 'Failed to fetch joke'}), 500

    return jsonify(joke)

@app.route('/api/jokes/<int:count>', methods=['GET'])
def api_get_multiple_jokes(count):
    """API endpoint untuk get multiple jokes"""
    if count > 20:
        count = 20

    jokes = generator.get_multiple_jokes(count)
    return jsonify({'jokes': jokes, 'count': len(jokes)})

